import React, { useState } from 'react';
import Icon from '../../../components/AppIcon';
import Button from '../../../components/ui/Button';

const DocumentDetailModal = ({ document, onClose, onApprove, onReject }) => {
  const [zoomLevel, setZoomLevel] = useState(100);

  const getDocumentTypeLabel = (type) => {
    const labels = {
      identity: 'Pièce d\'identité',
      address: 'Justificatif de domicile',
      other: 'Autre'
    };
    return labels?.[type] || type;
  };

  const getStatusConfig = (status) => {
    const configs = {
      pending: {
        label: 'En attente',
        icon: 'Clock',
        color: 'text-warning bg-warning/10'
      },
      approved: {
        label: 'Validé',
        icon: 'CheckCircle',
        color: 'text-success bg-success/10'
      },
      rejected: {
        label: 'Refusé',
        icon: 'XCircle',
        color: 'text-error bg-error/10'
      }
    };
    return configs?.[status] || configs?.pending;
  };

  const formatDate = (dateString) => {
    const date = new Date(dateString);
    return date?.toLocaleDateString('fr-FR', {
      day: '2-digit',
      month: 'long',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    });
  };

  const handleZoomIn = () => {
    setZoomLevel((prev) => Math.min(prev + 25, 200));
  };

  const handleZoomOut = () => {
    setZoomLevel((prev) => Math.max(prev - 25, 50));
  };

  const handleZoomReset = () => {
    setZoomLevel(100);
  };

  const statusConfig = getStatusConfig(document?.status);

  return (
    <div className="fixed inset-0 z-modal flex items-center justify-center p-4 bg-black/50">
      <div className="bg-white rounded-lg shadow-elevation-4 max-w-5xl w-full max-h-[90vh] overflow-y-auto">
        {/* Modal En-tête */}
        <div className="sticky top-0 bg-white border-b border-border px-6 py-4 flex items-center justify-between z-10">
          <div>
            <h2 className="text-xl font-semibold text-foreground">Examen du document</h2>
            <p className="text-sm text-muted-foreground mt-1">{document?.fileName}</p>
          </div>
          <button
            onClick={onClose}
            className="p-2 hover:bg-surface rounded-md transition-colors"
          >
            <Icon name="X" size={20} />
          </button>
        </div>

        {/* Modal Content */}
        <div className="p-6 space-y-6">
          {/* User Info */}
          <div className="bg-surface rounded-lg p-4 border border-border">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <p className="text-sm text-muted-foreground mb-1">Utilisateur</p>
                <p className="font-medium text-foreground">{document?.userPseudo}</p>
                <p className="text-sm text-muted-foreground">{document?.userEmail}</p>
              </div>
              <div>
                <p className="text-sm text-muted-foreground mb-1">Type de document</p>
                <p className="font-medium text-foreground">{getDocumentTypeLabel(document?.documentType)}</p>
              </div>
              <div>
                <p className="text-sm text-muted-foreground mb-1">Date de soumission</p>
                <p className="font-medium text-foreground">{formatDate(document?.uploadDate)}</p>
              </div>
              <div>
                <p className="text-sm text-muted-foreground mb-1">Statut actuel</p>
                <span className={`inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-medium ${statusConfig?.color}`}>
                  <Icon name={statusConfig?.icon} size={14} />
                  {statusConfig?.label}
                </span>
              </div>
            </div>

            {document?.status === 'approved' && document?.approvedDate && (
              <div className="mt-4 pt-4 border-t border-border">
                <p className="text-sm text-muted-foreground mb-1">Date de validation</p>
                <p className="font-medium text-foreground">{formatDate(document?.approvedDate)}</p>
              </div>
            )}

            {document?.status === 'rejected' && document?.rejectionReason && (
              <div className="mt-4 pt-4 border-t border-border">
                <p className="text-sm text-muted-foreground mb-1">Raison du refus</p>
                <p className="text-sm text-foreground">{document?.rejectionReason}</p>
                {document?.rejectedDate && (
                  <p className="text-xs text-muted-foreground mt-1">{formatDate(document?.rejectedDate)}</p>
                )}
              </div>
            )}
          </div>

          {/* Document Preview */}
          <div>
            <div className="flex items-center justify-between mb-3">
              <h3 className="font-semibold text-foreground flex items-center gap-2">
                <Icon name="FileText" size={18} />
                Aperçu du document
              </h3>
              <div className="flex items-center gap-2">
                <Button
                  size="sm"
                  variant="outline"
                  iconName="ZoomOut"
                  onClick={handleZoomOut}
                  disabled={zoomLevel <= 50}
                />
                <span className="text-sm text-muted-foreground min-w-[60px] text-center">{zoomLevel}%</span>
                <Button
                  size="sm"
                  variant="outline"
                  iconName="ZoomIn"
                  onClick={handleZoomIn}
                  disabled={zoomLevel >= 200}
                />
                <Button
                  size="sm"
                  variant="outline"
                  iconName="Maximize"
                  onClick={handleZoomReset}
                />
              </div>
            </div>
            <div className="bg-surface rounded-lg p-4 border border-border overflow-auto max-h-[500px]">
              <div className="flex items-center justify-center">
                <img
                  src={document?.thumbnail}
                  alt={document?.thumbnailAlt}
                  style={{ width: `${zoomLevel}%` }}
                  className="max-w-full h-auto rounded shadow-elevation-2"
                />
              </div>
            </div>
          </div>

          {/* Verification Checklist */}
          <div className="bg-[#17a2b8]/10 border border-[#17a2b8]/20 rounded-lg p-4">
            <h4 className="font-semibold text-foreground mb-3 flex items-center gap-2">
              <Icon name="CheckSquare" size={18} className="text-[#17a2b8]" />
              Points de vérification
            </h4>
            <ul className="space-y-2 text-sm text-foreground">
              <li className="flex items-start gap-2">
                <Icon name="Check" size={16} className="text-[#17a2b8] mt-0.5 flex-shrink-0" />
                <span>Le document est lisible et de bonne qualité</span>
              </li>
              <li className="flex items-start gap-2">
                <Icon name="Check" size={16} className="text-[#17a2b8] mt-0.5 flex-shrink-0" />
                <span>Les informations correspondent au type de document</span>
              </li>
              <li className="flex items-start gap-2">
                <Icon name="Check" size={16} className="text-[#17a2b8] mt-0.5 flex-shrink-0" />
                <span>Le document n'est pas expiré (si applicable)</span>
              </li>
              <li className="flex items-start gap-2">
                <Icon name="Check" size={16} className="text-[#17a2b8] mt-0.5 flex-shrink-0" />
                <span>Aucun signe de falsification ou modification</span>
              </li>
            </ul>
          </div>
        </div>

        {/* Modal Footer */}
        <div className="sticky bottom-0 bg-surface border-t border-border px-6 py-4 flex items-center justify-between">
          <Button variant="outline" onClick={onClose}>
            Fermer
          </Button>
          {document?.status === 'pending' && (
            <div className="flex gap-2">
              <Button
                variant="danger"
                iconName="XCircle"
                onClick={() => onReject(document?.id)}
              >
                Refuser
              </Button>
              <Button
                variant="success"
                iconName="CheckCircle"
                onClick={() => onApprove(document?.id)}
              >
                Valider
              </Button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default DocumentDetailModal;
