import React, { useState } from 'react';
import Icon from '../../../components/AppIcon';
import Button from '../../../components/ui/Button';
import Select from '../../../components/ui/Select';

const RejectDocumentModal = ({ onClose, onSubmit }) => {
  const [reason, setReason] = useState('');
  const [category, setCategory] = useState('');

  const rejectionCategories = [
    { value: 'quality', label: 'Document illisible ou de mauvaise qualité' },
    { value: 'expired', label: 'Document expiré' },
    { value: 'incomplete', label: 'Informations incomplètes ou manquantes' },
    { value: 'mismatch', label: 'Informations ne correspondent pas' },
    { value: 'type', label: 'Type de document incorrect' },
    { value: 'falsified', label: 'Suspicion de falsification' },
    { value: 'other', label: 'Autre raison' }
  ];

  const handleSubmit = () => {
    if (!category || !reason?.trim()) {
      alert('Veuillez sélectionner une catégorie et fournir une raison détaillée');
      return;
    }
    onSubmit(reason);
  };

  return (
    <div className="fixed inset-0 z-modal flex items-center justify-center p-4 bg-black/50">
      <div className="bg-white rounded-lg shadow-elevation-4 max-w-md w-full">
        {/* Modal En-tête */}
        <div className="border-b border-border px-6 py-4 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <Icon name="XCircle" size={20} className="text-error" />
            <h2 className="text-xl font-semibold text-foreground">Refuser le document</h2>
          </div>
          <button
            onClick={onClose}
            className="p-2 hover:bg-surface rounded-md transition-colors"
          >
            <Icon name="X" size={20} />
          </button>
        </div>

        {/* Modal Content */}
        <div className="p-6 space-y-4">
          <div className="bg-warning/10 border border-warning/20 rounded-lg p-3">
            <div className="flex gap-2">
              <Icon name="AlertTriangle" size={16} className="text-warning flex-shrink-0 mt-0.5" />
              <p className="text-xs text-foreground">
                L'utilisateur recevra une notification avec la raison du refus. Soyez précis pour l'aider à corriger le problème.
              </p>
            </div>
          </div>

          <Select
            label="Catégorie de refus"
            options={rejectionCategories}
            value={category}
            onChange={setCategory}
            placeholder="Sélectionnez une catégorie"
            required
          />

          <div>
            <label className="text-sm font-medium text-foreground mb-2 block">
              Raison détaillée <span className="text-error">*</span>
            </label>
            <textarea
              value={reason}
              onChange={(e) => setReason(e?.target?.value)}
              placeholder="Expliquez en détail pourquoi ce document est refusé et comment l'utilisateur peut le corriger..."
              rows={5}
              className="w-full rounded-md border border-input bg-background px-3 py-2 text-sm ring-offset-background placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 resize-none"
            />
          </div>
        </div>

        {/* Modal Footer */}
        <div className="bg-surface border-t border-border px-6 py-4 flex items-center justify-end gap-3">
          <Button variant="outline" onClick={onClose}>
            Annuler
          </Button>
          <Button
            variant="danger"
            iconName="XCircle"
            onClick={handleSubmit}
          >
            Confirmer le refus
          </Button>
        </div>
      </div>
    </div>
  );
};

export default RejectDocumentModal;
