import React, { useState } from 'react';
import Header from '../../components/navigation/Header';
import Footer from '../../components/Footer';
import Icon from '../../components/AppIcon';
import Button from '../../components/ui/Button';
import Select from '../../components/ui/Select';
import Input from '../../components/ui/Input';
import DocumentDetailModal from './components/DocumentDetailModal';
import RejectDocumentModal from './components/RejectDocumentModal';

const DocumentVerificationAdmin = () => {
  const [statusFilter, setStatusFilter] = useState('all');
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedDocument, setSelectedDocument] = useState(null);
  const [showDetailModal, setShowDetailModal] = useState(false);
  const [showRejectModal, setShowRejectModal] = useState(false);
  const [rejectDocumentId, setRejectDocumentId] = useState(null);

  const documents = [
  {
    id: 1,
    userPseudo: 'MarieDu',
    userEmail: 'marie.dubois@example.com',
    documentType: 'identity',
    fileName: 'carte_identite.pdf',
    uploadDate: '2026-02-14T10:30:00',
    status: 'pending',
    thumbnail: "/assets/images/no_image.png",
    thumbnailAlt: 'French national identity card document scan showing official government format',
    fileUrl: 'https://example.com/documents/carte_identite.pdf'
  },
  {
    id: 2,
    userPseudo: 'PierreM',
    userEmail: 'pierre.martin@example.com',
    documentType: 'address',
    fileName: 'facture_electricite.pdf',
    uploadDate: '2026-02-13T15:20:00',
    status: 'pending',
    thumbnail: "/assets/images/no_image.png",
    thumbnailAlt: 'Electricity bill document with address and account details visible',
    fileUrl: 'https://example.com/documents/facture_electricite.pdf'
  },
  {
    id: 3,
    userPseudo: 'SophieD',
    userEmail: 'sophie.durand@example.com',
    documentType: 'identity',
    fileName: 'passeport.pdf',
    uploadDate: '2026-02-12T09:15:00',
    status: 'approved',
    approvedDate: '2026-02-12T14:30:00',
    thumbnail: "/assets/images/no_image.png",
    thumbnailAlt: 'French passport document showing photo page with personal information',
    fileUrl: 'https://example.com/documents/passeport.pdf'
  },
  {
    id: 4,
    userPseudo: 'JeanP',
    userEmail: 'jean.petit@example.com',
    documentType: 'other',
    fileName: 'rib_bancaire.pdf',
    uploadDate: '2026-02-11T11:30:00',
    status: 'approved',
    approvedDate: '2026-02-11T16:00:00',
    thumbnail: "/assets/images/no_image.png",
    thumbnailAlt: 'Bank account details document showing IBAN and account holder information',
    fileUrl: 'https://example.com/documents/rib_bancaire.pdf'
  },
  {
    id: 5,
    userPseudo: 'LucB',
    userEmail: 'luc.bernard@example.com',
    documentType: 'address',
    fileName: 'facture_internet.pdf',
    uploadDate: '2026-02-10T14:45:00',
    status: 'rejected',
    rejectedDate: '2026-02-10T18:20:00',
    rejectionReason: 'Document illisible, veuillez télécharger une version de meilleure qualité',
    thumbnail: "/assets/images/no_image.png",
    thumbnailAlt: 'Internet service bill document with poor image quality',
    fileUrl: 'https://example.com/documents/facture_internet.pdf'
  },
  {
    id: 6,
    userPseudo: 'EmmaR',
    userEmail: 'emma.rousseau@example.com',
    documentType: 'identity',
    fileName: 'permis_conduire.pdf',
    uploadDate: '2026-02-14T08:00:00',
    status: 'pending',
    thumbnail: "/assets/images/no_image.png",
    thumbnailAlt: 'French driving license document showing photo and license details',
    fileUrl: 'https://example.com/documents/permis_conduire.pdf'
  }];


  const getStatusConfig = (status) => {
    const configs = {
      pending: {
        label: 'En attente',
        icon: 'Clock',
        color: 'text-warning bg-warning/10'
      },
      approved: {
        label: 'Validé',
        icon: 'CheckCircle',
        color: 'text-success bg-success/10'
      },
      rejected: {
        label: 'Refusé',
        icon: 'XCircle',
        color: 'text-error bg-error/10'
      }
    };
    return configs?.[status] || configs?.pending;
  };

  const getDocumentTypeLabel = (type) => {
    const labels = {
      identity: 'Pièce d\'identité',
      address: 'Justificatif de domicile',
      other: 'Autre'
    };
    return labels?.[type] || type;
  };

  const filteredDocuments = documents?.filter((doc) => {
    const matchesStatus = statusFilter === 'all' || doc?.status === statusFilter;
    const matchesSearch = !searchQuery ||
    doc?.userPseudo?.toLowerCase()?.includes(searchQuery?.toLowerCase()) ||
    doc?.userEmail?.toLowerCase()?.includes(searchQuery?.toLowerCase());
    return matchesStatus && matchesSearch;
  });

  const statusOptions = [
  { value: 'all', label: 'Tous les statuts' },
  { value: 'pending', label: 'En attente' },
  { value: 'approved', label: 'Validé' },
  { value: 'rejected', label: 'Refusé' }];


  const stats = [
  {
    label: 'En attente',
    value: documents?.filter((d) => d?.status === 'pending')?.length,
    icon: 'Clock',
    color: 'text-warning bg-warning/10'
  },
  {
    label: 'Validés',
    value: documents?.filter((d) => d?.status === 'approved')?.length,
    icon: 'CheckCircle',
    color: 'text-success bg-success/10'
  },
  {
    label: 'Refusés',
    value: documents?.filter((d) => d?.status === 'rejected')?.length,
    icon: 'XCircle',
    color: 'text-error bg-error/10'
  }];


  const handleViewDetails = (document) => {
    setSelectedDocument(document);
    setShowDetailModal(true);
  };

  const handleApprove = (documentId) => {
    console.log('Approve document:', documentId);
    // API call to approve document
    setShowDetailModal(false);
  };

  const handleReject = (documentId) => {
    setRejectDocumentId(documentId);
    setShowDetailModal(false);
    setShowRejectModal(true);
  };

  const handleRejectSubmit = (reason) => {
    console.log('Reject document:', rejectDocumentId, 'Reason:', reason);
    // API call to reject document with reason
    setShowRejectModal(false);
    setRejectDocumentId(null);
  };

  const formatDate = (dateString) => {
    const date = new Date(dateString);
    return date?.toLocaleDateString('fr-FR', {
      day: '2-digit',
      month: 'long',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    });
  };

  return (
    <div className="min-h-screen flex flex-col bg-surface">
      <Header />
      
      <main className="flex-1 container mx-auto px-4 py-6 md:py-8">
        {/* En-tête de page */}
        <div className="mb-6">
          <div className="flex items-center gap-2 text-sm text-muted-foreground mb-2">
            <a href="/administration-tableau-bord" className="hover:text-[#17a2b8] transition-colors">Admin</a>
            <Icon name="ChevronRight" size={14} />
            <span className="text-foreground">Vérification des documents</span>
          </div>
          <h1 className="text-2xl md:text-3xl font-bold text-foreground mb-2">Vérification des documents</h1>
          <p className="text-muted-foreground">Examinez et validez les documents soumis par les utilisateurs</p>
        </div>

        {/* Cartes de statistiques */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-6">
          {stats?.map((stat, index) =>
          <div key={index} className="bg-white rounded-lg shadow-elevation-1 p-4 md:p-6">
              <div className="flex items-start justify-between">
                <div className="flex-1">
                  <p className="text-sm text-muted-foreground mb-1">{stat?.label}</p>
                  <p className="text-3xl font-bold text-foreground">{stat?.value}</p>
                </div>
                <div className={`p-3 rounded-lg ${stat?.color}`}>
                  <Icon name={stat?.icon} size={24} />
                </div>
              </div>
            </div>
          )}
        </div>

        {/* Filtres */}
        <div className="bg-white rounded-lg shadow-elevation-1 p-4 mb-6">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <Input
              placeholder="Rechercher par pseudo ou e-mail..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e?.target?.value)}
              iconName="Search" />
            
            <Select
              options={statusOptions}
              value={statusFilter}
              onChange={setStatusFilter}
              placeholder="Filtrer par statut" />
            
          </div>
        </div>

        {/* Documents Table */}
        <div className="bg-white rounded-lg shadow-elevation-1 overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead className="bg-surface border-b border-border">
                <tr>
                  <th className="px-4 md:px-6 py-3 text-left text-xs font-medium text-muted-foreground uppercase tracking-wider">
                    Utilisateur
                  </th>
                  <th className="px-4 md:px-6 py-3 text-left text-xs font-medium text-muted-foreground uppercase tracking-wider">
                    Type de document
                  </th>
                  <th className="px-4 md:px-6 py-3 text-left text-xs font-medium text-muted-foreground uppercase tracking-wider">
                    Date de soumission
                  </th>
                  <th className="px-4 md:px-6 py-3 text-left text-xs font-medium text-muted-foreground uppercase tracking-wider">
                    Statut
                  </th>
                  <th className="px-4 md:px-6 py-3 text-right text-xs font-medium text-muted-foreground uppercase tracking-wider">
                    Actions
                  </th>
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {filteredDocuments?.length === 0 ?
                <tr>
                    <td colSpan="5" className="px-6 py-12 text-center">
                      <Icon name="FileText" size={48} className="mx-auto text-muted-foreground mb-3" />
                      <p className="text-muted-foreground">Aucun document trouvé</p>
                    </td>
                  </tr> :

                filteredDocuments?.map((doc) => {
                  const statusConfig = getStatusConfig(doc?.status);
                  return (
                    <tr key={doc?.id} className="hover:bg-surface transition-colors">
                        <td className="px-4 md:px-6 py-4">
                          <div className="flex items-center gap-3">
                            <div className="w-12 h-12 flex-shrink-0">
                              <img
                              src={doc?.thumbnail}
                              alt={doc?.thumbnailAlt}
                              className="w-full h-full object-cover rounded border border-border" />
                            
                            </div>
                            <div>
                              <p className="font-medium text-foreground">{doc?.userPseudo}</p>
                              <p className="text-sm text-muted-foreground">{doc?.userEmail}</p>
                            </div>
                          </div>
                        </td>
                        <td className="px-4 md:px-6 py-4">
                          <p className="text-sm text-foreground">{getDocumentTypeLabel(doc?.documentType)}</p>
                          <p className="text-xs text-muted-foreground">{doc?.fileName}</p>
                        </td>
                        <td className="px-4 md:px-6 py-4">
                          <p className="text-sm text-foreground">{formatDate(doc?.uploadDate)}</p>
                        </td>
                        <td className="px-4 md:px-6 py-4">
                          <span className={`inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-medium ${statusConfig?.color}`}>
                            <Icon name={statusConfig?.icon} size={14} />
                            {statusConfig?.label}
                          </span>
                        </td>
                        <td className="px-4 md:px-6 py-4 text-right">
                          <div className="flex items-center justify-end gap-2">
                            <Button
                            size="sm"
                            variant="outline"
                            iconName="Eye"
                            onClick={() => handleViewDetails(doc)}>
                            
                              Examiner
                            </Button>
                            {doc?.status === 'pending' &&
                          <>
                                <Button
                              size="sm"
                              variant="success"
                              iconName="CheckCircle"
                              onClick={() => handleApprove(doc?.id)}>
                              
                                  Valider
                                </Button>
                                <Button
                              size="sm"
                              variant="danger"
                              iconName="XCircle"
                              onClick={() => handleReject(doc?.id)}>
                              
                                  Refuser
                                </Button>
                              </>
                          }
                          </div>
                        </td>
                      </tr>);

                })
                }
              </tbody>
            </table>
          </div>
        </div>
      </main>

      <Footer />

      {/* Modals */}
      {showDetailModal && selectedDocument &&
      <DocumentDetailModal
        document={selectedDocument}
        onClose={() => setShowDetailModal(false)}
        onApprove={handleApprove}
        onReject={handleReject} />

      }

      {showRejectModal &&
      <RejectDocumentModal
        onClose={() => setShowRejectModal(false)}
        onSubmit={handleRejectSubmit} />

      }
    </div>);

};

export default DocumentVerificationAdmin;


